1	package com.pharmaprocure.portal.security;
2	
3	import com.fasterxml.jackson.databind.ObjectMapper;
4	import com.pharmaprocure.portal.dto.ApiErrorResponse;
5	import jakarta.servlet.FilterChain;
6	import jakarta.servlet.ServletException;
7	import jakarta.servlet.http.HttpServletRequest;
8	import jakarta.servlet.http.HttpServletResponse;
9	import java.io.IOException;
10	import java.time.Clock;
11	import java.time.Instant;
12	import java.util.ArrayDeque;
13	import java.util.Deque;
14	import java.util.List;
15	import java.util.Map;
16	import java.util.concurrent.ConcurrentHashMap;
17	import org.springframework.http.MediaType;
18	import org.springframework.beans.factory.annotation.Autowired;
19	import org.springframework.security.authentication.AnonymousAuthenticationToken;
20	import org.springframework.security.core.Authentication;
21	import org.springframework.security.core.context.SecurityContextHolder;
22	import org.springframework.stereotype.Component;
23	import org.springframework.web.filter.OncePerRequestFilter;
24	
25	@Component
26	public class RateLimitFilter extends OncePerRequestFilter {
27	
28	    private static final int MAX_REQUESTS_PER_MINUTE = 60;
29	    private final Map<String, Deque<Instant>> requestWindows = new ConcurrentHashMap<>();
30	    private final Clock clock;
31	    private final ObjectMapper objectMapper;
32	
33	    @Autowired
34	    public RateLimitFilter(ObjectMapper objectMapper) {
35	        this(objectMapper, Clock.systemUTC());
36	    }
37	
38	    RateLimitFilter(ObjectMapper objectMapper, Clock clock) {
39	        this.objectMapper = objectMapper;
40	        this.clock = clock;
41	    }
42	
43	    @Override
44	    protected boolean shouldNotFilter(HttpServletRequest request) {
45	        String path = request.getRequestURI();
46	        return path.startsWith("/api/health") || path.startsWith("/api/meta") || path.startsWith("/actuator") || path.startsWith("/api/auth");
47	    }
48	
49	    @Override
50	    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response, FilterChain filterChain) throws ServletException, IOException {
51	        Authentication authentication = SecurityContextHolder.getContext().getAuthentication();
52	        if (authentication == null || !authentication.isAuthenticated() || authentication instanceof AnonymousAuthenticationToken) {
53	            filterChain.doFilter(request, response);
54	            return;
55	        }
56	
57	        String key = authentication.getName();
58	        Deque<Instant> window = requestWindows.computeIfAbsent(key, ignored -> new ArrayDeque<>());
59	        Instant now = clock.instant();
60	
61	        synchronized (window) {
62	            while (!window.isEmpty() && window.peekFirst().isBefore(now.minusSeconds(60))) {
63	                window.pollFirst();
64	            }
65	            if (window.size() >= MAX_REQUESTS_PER_MINUTE) {
66	                response.setStatus(429);
67	                response.setContentType(MediaType.APPLICATION_JSON_VALUE);
68	                objectMapper.writeValue(response.getOutputStream(), new ApiErrorResponse(429, "Rate limit exceeded", List.of("MAX_60_REQUESTS_PER_MINUTE")));
69	                return;
70	            }
71	            window.addLast(now);
72	        }
73	
74	        filterChain.doFilter(request, response);
75	    }
76	}
