35	@SpringBootTest
36	@AutoConfigureMockMvc
37	@ActiveProfiles("test")
38	@Transactional
39	abstract class AbstractMockMvcIntegrationTest {
40	
41	    @Autowired
42	    protected MockMvc mockMvc;
43	
44	    @Autowired
45	    protected com.fasterxml.jackson.databind.ObjectMapper objectMapper;
46	
47	    @Autowired
48	    protected RoleRepository roleRepository;
49	
50	    @Autowired
51	    protected UserRepository userRepository;
52	
53	    @Autowired
54	    protected ProductCatalogRepository productCatalogRepository;
55	
56	    @Autowired
57	    protected ProcurementOrderRepository orderRepository;
58	
59	    @Autowired
60	    protected OrderStateMachineDefinitionRepository orderStateMachineDefinitionRepository;
61	
62	    @Autowired
63	    protected PasswordEncoder passwordEncoder;
64	
65	    @Autowired
66	    protected RolePermissionMatrix rolePermissionMatrix;
67	
68	    @BeforeEach
69	    void seedStateMachine() {
70	        if (!orderStateMachineDefinitionRepository.findByActiveTrue().isEmpty()) {
71	            return;
72	        }
73	        saveTransition(OrderStatus.CREATED, OrderStatus.UNDER_REVIEW);
74	        saveTransition(OrderStatus.UNDER_REVIEW, OrderStatus.APPROVED);
75	        saveTransition(OrderStatus.UNDER_REVIEW, OrderStatus.CANCELED);
76	        saveTransition(OrderStatus.APPROVED, OrderStatus.PAYMENT_RECORDED);
77	        saveTransition(OrderStatus.PAYMENT_RECORDED, OrderStatus.PICK_PACK);
78	        saveTransition(OrderStatus.PICK_PACK, OrderStatus.PARTIALLY_SHIPPED);
79	        saveTransition(OrderStatus.PICK_PACK, OrderStatus.SHIPPED);
80	        saveTransition(OrderStatus.PARTIALLY_SHIPPED, OrderStatus.SHIPPED);
81	        saveTransition(OrderStatus.PARTIALLY_SHIPPED, OrderStatus.RETURNED);
82	        saveTransition(OrderStatus.SHIPPED, OrderStatus.RECEIVED);
83	        saveTransition(OrderStatus.SHIPPED, OrderStatus.RETURNED);
84	        saveTransition(OrderStatus.RECEIVED, OrderStatus.RETURNED);
85	    }
86	
87	    protected UserEntity createUser(RoleName roleName, String username, String organizationCode, String rawPassword) {
88	        RoleEntity role = roleRepository.findByName(roleName).orElseGet(() -> {
89	            RoleEntity entity = new RoleEntity();
90	            entity.setName(roleName);
91	            return roleRepository.save(entity);
92	        });
93	        UserEntity user = new UserEntity();
94	        user.setUsername(username);
95	        user.setPasswordHash(passwordEncoder.encode(rawPassword));
96	        user.setDisplayName(username);
97	        user.setOrganizationCode(organizationCode);
98	        user.setRole(role);
99	        user.setActive(true);
100	        return userRepository.save(user);
101	    }
102	
103	    protected ProcurementOrderEntity createOrder(UserEntity buyer, OrderStatus status, int orderedQuantity, int shippedQuantity, int receivedQuantity) {
104	        ProductCatalogEntity product = new ProductCatalogEntity();
105	        String suffix = UUID.randomUUID().toString().substring(0, 8).toUpperCase();
106	        product.setSku("PP-TEST-" + suffix);
107	        product.setName("Test Product " + suffix);
108	        product.setUnit("box");
109	        product.setUnitPrice(BigDecimal.valueOf(12.50));
110	        product = productCatalogRepository.save(product);
111	
112	        ProcurementOrderEntity order = new ProcurementOrderEntity();
113	        order.setOrderNumber("ORD-" + suffix);
114	        order.setBuyer(buyer);
115	        order.setCurrentStatus(status);
116	        order.setPaymentRecorded(status != OrderStatus.CREATED && status != OrderStatus.UNDER_REVIEW && status != OrderStatus.APPROVED);
117	        order.setReviewRequired(true);
118	        order.setCreatedAt(OffsetDateTime.now());
119	        order.setUpdatedAt(OffsetDateTime.now());
120	
121	        ProcurementOrderItemEntity item = new ProcurementOrderItemEntity();
122	        item.setOrder(order);
123	        item.setProduct(product);
124	        item.setProductNameSnapshot(product.getName());
125	        item.setSkuSnapshot(product.getSku());
126	        item.setUnitSnapshot(product.getUnit());
127	        item.setUnitPriceSnapshot(product.getUnitPrice());
128	        item.setOrderedQuantity(orderedQuantity);
129	        item.setShippedQuantity(shippedQuantity);
130	        item.setReceivedQuantity(receivedQuantity);
131	        item.setReturnedQuantity(0);
132	        item.setDamagedQuantity(0);
133	        item.setDiscrepancyFlag(false);
134	        order.getItems().add(item);
135	
136	        return orderRepository.save(order);
137	    }
138	
139	    protected RequestPostProcessor authenticated(UserEntity user) {
140	        return SecurityMockMvcRequestPostProcessors.user(principal(user));
141	    }
142	
143	    protected String json(Object value) throws JsonProcessingException {
144	        return objectMapper.writeValueAsString(value);
145	    }
146	
147	    protected UserPrincipal principal(UserEntity user) {
148	        return new UserPrincipal(
149	            user.getId(),
150	            user.getUsername(),
151	            user.getDisplayName(),
152	            user.getOrganizationCode(),
153	            user.getPasswordHash(),
154	            user.getRole().getName(),
155	            Set.copyOf(rolePermissionMatrix.getGrants(user.getRole().getName())),
156	            user.isActive()
157	        );
158	    }
159	
160	    private void saveTransition(OrderStatus from, OrderStatus to) {
161	        OrderStateMachineDefinitionEntity entity = new OrderStateMachineDefinitionEntity();
162	        entity.setFromStatus(from.name());
163	        entity.setToStatus(to.name());
164	        entity.setActive(true);
165	        orderStateMachineDefinitionRepository.save(entity);
166	    }
167	}
