3	import com.pharmaprocure.portal.dto.CriticalActionDtos.CreateCriticalActionRequest;
4	import com.pharmaprocure.portal.dto.CriticalActionDtos.CriticalActionApprovalResponse;
5	import com.pharmaprocure.portal.dto.CriticalActionDtos.CriticalActionAuditResponse;
6	import com.pharmaprocure.portal.dto.CriticalActionDtos.CriticalActionRequestResponse;
7	import com.pharmaprocure.portal.entity.CriticalActionApprovalEntity;
8	import com.pharmaprocure.portal.entity.CriticalActionRequestEntity;
9	import com.pharmaprocure.portal.entity.DocumentEntity;
10	import com.pharmaprocure.portal.entity.ProcurementOrderEntity;
11	import com.pharmaprocure.portal.entity.UserEntity;
12	import com.pharmaprocure.portal.enums.DataScope;
13	import com.pharmaprocure.portal.enums.CriticalActionAuditAction;
14	import com.pharmaprocure.portal.enums.CriticalActionDecision;
15	import com.pharmaprocure.portal.enums.CriticalActionRequestType;
16	import com.pharmaprocure.portal.enums.CriticalActionStatus;
17	import com.pharmaprocure.portal.enums.CriticalActionTargetType;
18	import com.pharmaprocure.portal.enums.DocumentStatus;
19	import com.pharmaprocure.portal.enums.OrderStatus;
20	import com.pharmaprocure.portal.exception.ApiException;
21	import com.pharmaprocure.portal.repository.CriticalActionApprovalRepository;
22	import com.pharmaprocure.portal.repository.CriticalActionAuditEventRepository;
23	import com.pharmaprocure.portal.repository.CriticalActionRequestRepository;
24	import com.pharmaprocure.portal.repository.DocumentRepository;
25	import com.pharmaprocure.portal.repository.ProcurementOrderRepository;
26	import com.pharmaprocure.portal.security.Permission;
27	import com.pharmaprocure.portal.security.PermissionAuthorizationService;
28	import com.pharmaprocure.portal.security.UserPrincipal;
29	import java.time.OffsetDateTime;
30	import java.util.List;
31	import org.springframework.stereotype.Service;
32	import org.springframework.transaction.annotation.Transactional;
33	
34	@Service
35	public class CriticalActionService {
36	
37	    private final CriticalActionRequestRepository requestRepository;
38	    private final CriticalActionApprovalRepository approvalRepository;
39	    private final CriticalActionAuditEventRepository auditRepository;
40	    private final CurrentUserService currentUserService;
41	    private final CriticalActionAuditService auditService;
42	    private final ProcurementOrderRepository orderRepository;
43	    private final DocumentRepository documentRepository;
44	    private final PermissionAuthorizationService permissionAuthorizationService;
45	
46	    public CriticalActionService(
47	        CriticalActionRequestRepository requestRepository,
48	        CriticalActionApprovalRepository approvalRepository,
49	        CriticalActionAuditEventRepository auditRepository,
50	        CurrentUserService currentUserService,
51	        CriticalActionAuditService auditService,
52	        ProcurementOrderRepository orderRepository,
53	        DocumentRepository documentRepository,
54	        PermissionAuthorizationService permissionAuthorizationService
55	    ) {
56	        this.requestRepository = requestRepository;
57	        this.approvalRepository = approvalRepository;
58	        this.auditRepository = auditRepository;
59	        this.currentUserService = currentUserService;
60	        this.auditService = auditService;
61	        this.orderRepository = orderRepository;
62	        this.documentRepository = documentRepository;
63	        this.permissionAuthorizationService = permissionAuthorizationService;
64	    }
65	
66	    @Transactional
67	    public List<CriticalActionRequestResponse> list() {
68	        UserEntity actor = currentUserService.requireCurrentUser();
69	        DataScope scope = permissionAuthorizationService.requireDataScope(actor, Permission.CRITICAL_ACTION_VIEW);
70	        List<CriticalActionRequestEntity> requests = switch (scope) {
71	            case SELF -> requestRepository.findByRequestedByIdOrderByCreatedAtDesc(actor.getId());
72	            case ORGANIZATION -> requestRepository.findByRequestedByOrganizationCodeOrderByCreatedAtDesc(actor.getOrganizationCode());
73	            case TEAM, GLOBAL -> requestRepository.findAllByOrderByCreatedAtDesc();
74	        };
75	        requests = permissionAuthorizationService.filterByScope(
76	            actor,
77	            Permission.CRITICAL_ACTION_VIEW,
78	            requests,
79	            request -> request.getRequestedBy().getId(),
80	            request -> request.getRequestedBy().getRole().getName(),
81	            request -> request.getRequestedBy().getOrganizationCode()
82	        );
83	        requests.forEach(this::expireIfNeeded);
84	        return requests.stream().map(this::toResponse).toList();
85	    }
86	
87	    @Transactional
88	    public CriticalActionRequestResponse create(CreateCriticalActionRequest request) {
89	        UserEntity actor = currentUserService.requireCurrentUser();
90	        CriticalActionRequestType requestType = CriticalActionRequestType.valueOf(request.requestType());
91	        CriticalActionTargetType targetType = CriticalActionTargetType.valueOf(request.targetType());
92	        validateTarget(requestType, targetType, request.targetId(), actor);
93	        requestRepository.findByRequestTypeAndTargetTypeAndTargetIdAndStatusIn(requestType, targetType, request.targetId(), List.of(CriticalActionStatus.PENDING, CriticalActionStatus.PARTIALLY_APPROVED))
94	            .ifPresent(existing -> { throw new ApiException(400, "Active critical action request already exists", List.of("requestId=" + existing.getId())); });
95	
96	        CriticalActionRequestEntity entity = new CriticalActionRequestEntity();
97	        entity.setRequestType(requestType);
98	        entity.setTargetType(targetType);
99	        entity.setTargetId(request.targetId());
100	        entity.setJustification(request.justification());
101	        entity.setRequestedBy(actor);
102	        entity.setStatus(CriticalActionStatus.PENDING);
103	        entity.setCreatedAt(OffsetDateTime.now());
104	        entity.setExpiresAt(OffsetDateTime.now().plusHours(24));
105	        entity = requestRepository.save(entity);
106	        auditService.record(entity, actor, CriticalActionAuditAction.REQUESTED, request.justification());
107	        return toResponse(entity);
108	    }
109	
110	    @Transactional
111	    public CriticalActionRequestResponse decide(Long requestId, CriticalActionDecision decision, String comments) {
112	        UserEntity actor = currentUserService.requireCurrentUser();
113	        CriticalActionRequestEntity request = requireRequest(requestId, actor, Permission.CRITICAL_ACTION_VIEW);
114	        expireIfNeeded(request);
115	        if (request.getStatus() == CriticalActionStatus.EXPIRED) {
116	            throw new ApiException(400, "Critical action request has expired", List.of("requestId=" + requestId));
117	        }
118	        if (request.getStatus() == CriticalActionStatus.EXECUTED || request.getStatus() == CriticalActionStatus.REJECTED) {
119	            throw new ApiException(400, "Critical action request is already resolved", List.of(request.getStatus().name()));
120	        }
121	        if (approvalRepository.findByRequestIdAndApproverUserId(requestId, actor.getId()).isPresent()) {
122	          throw new ApiException(400, "The same user cannot approve twice", List.of("SAME_USER_REJECTION"));
123	        }
124	
125	        CriticalActionApprovalEntity approval = new CriticalActionApprovalEntity();
126	        approval.setRequest(request);
127	        approval.setApproverUser(actor);
128	        approval.setDecision(decision);
129	        approval.setComments(comments);
130	        approval.setCreatedAt(OffsetDateTime.now());
131	        approvalRepository.save(approval);
132	
133	        if (decision == CriticalActionDecision.REJECT) {
134	            request.setStatus(CriticalActionStatus.REJECTED);
135	            request.setResolvedAt(OffsetDateTime.now());
136	            request.setResolutionNote(comments == null ? "Rejected" : comments);
137	            auditService.record(request, actor, CriticalActionAuditAction.REJECTED, comments);
138	            return toResponse(request);
139	        }
140	
141	        List<CriticalActionApprovalEntity> approvals = approvalRepository.findByRequestIdOrderByCreatedAtAsc(requestId);
142	        if (approvals.size() == 1) {
143	            request.setStatus(CriticalActionStatus.PARTIALLY_APPROVED);
144	            auditService.record(request, actor, CriticalActionAuditAction.APPROVED, "First approval recorded");
145	        } else if (approvals.size() >= 2) {
146	            request.setStatus(CriticalActionStatus.APPROVED);
147	            request.setResolvedAt(OffsetDateTime.now());
148	            request.setResolutionNote("Two distinct approvals recorded");
149	            auditService.record(request, actor, CriticalActionAuditAction.APPROVED, "Second approval recorded");
150	            execute(request, actor);
151	        }
152	        return toResponse(request);
153	    }
154	
155	    @Transactional
156	    public CriticalActionRequestResponse get(Long requestId, UserPrincipal principal) {
157	        UserEntity actor = currentUserService.requireCurrentUser();
158	        if (!actor.getId().equals(principal.id())) {
159	            throw new ApiException(403, "Access denied", List.of("AUTH_CONTEXT_MISMATCH"));
160	        }
161	        CriticalActionRequestEntity request = requireRequest(requestId, actor, Permission.CRITICAL_ACTION_VIEW);
162	        expireIfNeeded(request);
163	        return toResponse(request);
164	    }
165	
166	    private void execute(CriticalActionRequestEntity request, UserEntity actor) {
167	        switch (request.getRequestType()) {
168	            case ORDER_CANCELLATION_AFTER_APPROVAL -> executeOrderCancellation(request, actor);
169	            case DOCUMENT_DESTRUCTION -> executeDocumentDestruction(request, actor);
170	            case RETENTION_OVERRIDE -> executeRetentionOverride(request, actor);
171	        }
172	        request.setStatus(CriticalActionStatus.EXECUTED);
173	        request.setResolvedAt(OffsetDateTime.now());
174	        auditService.record(request, actor, CriticalActionAuditAction.EXECUTED, request.getRequestType().name());
175	    }
176	
177	    private void executeOrderCancellation(CriticalActionRequestEntity request, UserEntity actor) {
178	        ProcurementOrderEntity order = orderRepository.findWithItemsById(request.getTargetId())
179	            .orElseThrow(() -> new ApiException(404, "Order not found", List.of("orderId=" + request.getTargetId())));
180	        order.setCurrentStatus(OrderStatus.CANCELED);
181	        order.setUpdatedAt(OffsetDateTime.now());
182	    }
183	
184	    private void executeDocumentDestruction(CriticalActionRequestEntity request, UserEntity actor) {
185	        DocumentEntity document = documentRepository.findWithCurrentVersionById(request.getTargetId())
186	            .orElseThrow(() -> new ApiException(404, "Document not found", List.of("documentId=" + request.getTargetId())));
187	        document.setStatus(DocumentStatus.DESTROYED);
188	        document.setDestroyedAt(OffsetDateTime.now());
189	        document.setDestroyedBy(actor);
190	        document.setUpdatedAt(OffsetDateTime.now());
191	    }
192	
193	    private void executeRetentionOverride(CriticalActionRequestEntity request, UserEntity actor) {
194	        DocumentEntity document = documentRepository.findWithCurrentVersionById(request.getTargetId())
195	            .orElseThrow(() -> new ApiException(404, "Document not found", List.of("documentId=" + request.getTargetId())));
196	        document.setRetentionOverrideUntil(OffsetDateTime.now().plusDays(365));
197	        document.setUpdatedAt(OffsetDateTime.now());
198	    }
199	
200	    private void validateTarget(CriticalActionRequestType requestType, CriticalActionTargetType targetType, Long targetId, UserEntity actor) {
201	        switch (requestType) {
202	            case ORDER_CANCELLATION_AFTER_APPROVAL -> {
203	                if (targetType != CriticalActionTargetType.ORDER) {
204	                    throw new ApiException(400, "Invalid target type for order cancellation", List.of(targetType.name()));
205	                }
206	                ProcurementOrderEntity order = orderRepository.findWithItemsById(targetId)
207	                    .orElseThrow(() -> new ApiException(404, "Order not found", List.of("orderId=" + targetId)));
208	                boolean allowed = permissionAuthorizationService.canAccessResource(
209	                    actor,
210	                    Permission.CRITICAL_ACTION_REQUEST,
211	                    order.getBuyer().getId(),
212	                    order.getBuyer().getRole().getName(),
213	                    order.getBuyer().getOrganizationCode()
214	                );
215	                if (!allowed) {
216	                    throw new ApiException(403, "Access denied", List.of("ORDER_SCOPE_RESTRICTION"));
217	                }
218	                if (order.getCurrentStatus() != OrderStatus.APPROVED && order.getCurrentStatus() != OrderStatus.PAYMENT_RECORDED && order.getCurrentStatus() != OrderStatus.PICK_PACK && order.getCurrentStatus() != OrderStatus.PARTIALLY_SHIPPED && order.getCurrentStatus() != OrderStatus.SHIPPED) {
219	                    throw new ApiException(400, "Only approved or fulfilled orders require critical cancellation", List.of(order.getCurrentStatus().name()));
220	                }
221	            }
222	            case DOCUMENT_DESTRUCTION, RETENTION_OVERRIDE -> {
223	                if (targetType != CriticalActionTargetType.DOCUMENT) {
224	                    throw new ApiException(400, "Invalid target type for document action", List.of(targetType.name()));
225	                }
226	                DocumentEntity document = documentRepository.findWithCurrentVersionById(targetId)
227	                    .orElseThrow(() -> new ApiException(404, "Document not found", List.of("documentId=" + targetId)));
228	                boolean allowed = permissionAuthorizationService.canAccessResource(
