233	                    document.getOwnerUser().getOrganizationCode()
234	                );
235	                if (!allowed) {
236	                    throw new ApiException(403, "Access denied", List.of("DOCUMENT_SCOPE_RESTRICTION"));
237	                }
238	            }
239	        }
240	    }
