258	    private void expireIfNeeded(CriticalActionRequestEntity request) {
259	        if ((request.getStatus() == CriticalActionStatus.PENDING || request.getStatus() == CriticalActionStatus.PARTIALLY_APPROVED) && request.getExpiresAt().isBefore(OffsetDateTime.now())) {
260	            request.setStatus(CriticalActionStatus.EXPIRED);
261	            request.setResolvedAt(OffsetDateTime.now());
262	            request.setResolutionNote("Expired after 24 hours without two approvals");
263	            auditService.record(request, request.getRequestedBy(), CriticalActionAuditAction.EXPIRED, request.getResolutionNote());
264	        }
265	    }
