66	
67	  constructor(
68	    private readonly fb: FormBuilder,
69	    public readonly documentCenterService: DocumentCenterService,
70	    private readonly snackBar: MatSnackBar,
71	    private readonly authService: AuthService,
72	    private readonly criticalActionService: CriticalActionService
73	  ) {}
74	
75	  ngOnInit(): void {
76	    this.reload();
77	  }
78	
79	  onFileSelected(event: Event): void {
80	    const input = event.target as HTMLInputElement;
81	    this.selectedFile = input.files?.item(0) ?? null;
82	  }
83	
84	  createTemplate(): void {
85	    if (!this.startAction(this.templateActionKey())) {
86	      return;
87	    }
88	    if (this.templateForm.invalid) {
89	      this.finishAction(this.templateActionKey());
90	      this.templateForm.markAllAsTouched();
91	      return;
92	    }
93	    this.documentCenterService.createTemplate(this.templateForm.getRawValue()).pipe(
94	      finalize(() => this.finishAction(this.templateActionKey()))
95	    ).subscribe({
96	      next: () => {
97	        this.snackBar.open('Template created', 'Dismiss', { duration: 2200 });
98	        this.reload();
99	      }
100	    });
101	  }
102	
103	  createDraft(): void {
104	    if (!this.startAction(this.draftActionKey())) {
105	      return;
106	    }
107	    if (this.draftForm.invalid) {
108	      this.finishAction(this.draftActionKey());
109	      this.draftForm.markAllAsTouched();
110	      return;
111	    }
112	    this.documentCenterService.createDraft(JSON.stringify(this.draftForm.getRawValue()), this.selectedFile).pipe(
113	      finalize(() => this.finishAction(this.draftActionKey()))
